import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { StarIcon } from "lucide-react";

const ProductCard = ({
  id,
  name,
  price,
  originalPrice,
  images,
  rating,
  reviewCount,
  isOnSale,
  discountPercentage,
  onAddToCart,
  onQuickView,
  className
}: ProductCardProps) => {
  const discount = originalPrice ? Math.round(((originalPrice - price) / originalPrice) * 100) : discountPercentage;

  return (
    <Card className={cn("group relative overflow-hidden transition-all hover:shadow-lg", className)}>
      {/* Badge promotion */}
      {isOnSale && discount && discount > 0 && (
        <Badge className="absolute top-3 left-3 z-10 bg-red-500 hover:bg-red-600">
          -{discount}%
        </Badge>
      )}

      {/* Image avec lazy loading */}
      <div className="aspect-square overflow-hidden bg-gray-100">
        <img 
          src={images[0]} 
          alt={name}
          className="h-full w-full object-cover transition-transform group-hover:scale-105"
          loading="lazy"
        />
      </div>

      <CardContent className="p-4">
        <h3 className="font-semibold text-lg line-clamp-1">{name}</h3>

        {/* Affichage des étoiles */}
        <div className="flex items-center gap-1 mt-1">
          <div className="flex">
            {[...Array(5)].map((_, i) => (
              <StarIcon key={i} className={`h-4 w-4 ${i < Math.floor(rating) ? 'fill-yellow-400 text-yellow-400' : 'text-gray-300'}`} />
            ))}
          </div>
          <span className="text-xs text-gray-500">({reviewCount})</span>
        </div>

        {/* Prix */}
        <div className="mt-2 flex items-baseline gap-2">
          <span className="text-xl font-bold text-primary">{price.toFixed(2)} €</span>
          {originalPrice && originalPrice > price && (
            <span className="text-sm text-gray-400 line-through">{originalPrice.toFixed(2)} €</span>
          )}
        </div>

        {/* Boutons d'action */}
        <div className="mt-4 flex gap-2">
          <Button 
            className="flex-1" 
            onClick={() => onAddToCart(id, 1)}
          >
            Ajouter au panier
          </Button>
          {onQuickView && (
            <Button variant="outline" size="icon" onClick={() => onQuickView(id)}>
              <EyeIcon className="h-4 w-4" />
            </Button>
          )}
        </div>
      </CardContent>
    </Card>
  );
};

export default React.memo(ProductCard);
```

